index 9df08553d86e..2bb2b91534cb 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
@@ -8790,8 +8790,108 @@ Instruction *InstCombinerImpl::visitFCmpInst(FCmpInst &I) {
     }
   }

-  // Convert a sign-bit test of an FP value into a cast and integer compare.
-  // TODO: Simplify if the copysign constant is 0.0 or NaN.
+  // fcmp (fptrunc X), C -> fcmp X, threshold(C, pred)
+  // Fold comparison of truncated value to a comparison of the original value
+  // to a computed threshold. For round-to-nearest truncation, the threshold
+  // is the midpoint between C and the adjacent float value.
+  if (match(Op0, m_FPTrunc(m_Value(X)))) {
+    Type *SrcTy = X->getType()->getScalarType();
+    Type *TruncTy = Op0->getType()->getScalarType();
+    const APFloat *C;
+    const fltSemantics &SrcSem = SrcTy->getFltSemantics();
+    const fltSemantics &TruncSem = TruncTy->getFltSemantics();
+    
+    // Only handle different IEEE-like floating point types where source is wider
+    if (SrcTy->isFloatingPointTy() && TruncTy->isFloatingPointTy() &&
+        &SrcSem != &TruncSem && TruncTy->isIEEELikeFPTy() &&
+        SrcTy->getFPMantissaWidth() > TruncTy->getFPMantissaWidth() &&
+        match(Op1, m_APFloat(C))) {
+      
+      // Determine which adjacent float value we need based on predicate
+      // For oge/ult: need midpoint(C, prev_float(C))
+      // For ole/ogt: need midpoint(C, next_float(C))
+      bool NeedPrevFloat = (Pred == FCmpInst::FCMP_OGE ||
+                            Pred == FCmpInst::FCMP_UGE ||
+                            Pred == FCmpInst::FCMP_ULT);
+      bool NeedNextFloat = (Pred == FCmpInst::FCMP_OLE ||
+                            Pred == FCmpInst::FCMP_ULE ||
+                            Pred == FCmpInst::FCMP_OGT ||
+                            Pred == FCmpInst::FCMP_UGT);
+      
+      if (NeedPrevFloat || NeedNextFloat) {
+        // Get the bit representation of C
+        APFloat TruncC = *C;
+        
+        // Check for special values (infinity, NaN) - cannot compute adjacent
+        if (TruncC.isInfinity() || TruncC.isNaN())
+          continue;
+        
+        APInt TruncBits = TruncC.bitcastToAPInt();
+        unsigned BitWidth = TruncBits.getBitWidth();
+        
+        // To get adjacent float, we need to manipulate bits correctly.
+        // The trick is to convert to "ordered integer representation" where
+        // integer comparison matches float comparison.
+        // For positive: flip sign bit. For negative: flip all bits.
+        APInt SignBit = APInt(BitWidth, 1) << (BitWidth - 1);
+        bool IsNegative = TruncBits.ugt(SignBit - 1); // sign bit is set
+        
+        APInt OrderedBits;
+        if (IsNegative) {
+          OrderedBits = ~TruncBits;
+        } else {
+          OrderedBits = TruncBits ^ SignBit;
+        }
+        
+        // Now add/subtract 1 to move in the desired direction
+        if (NeedPrevFloat) {
+          // Toward -inf: subtract 1 in ordered representation
+          OrderedBits = OrderedBits - APInt(BitWidth, 1);
+        } else {
+          // Toward +inf: add 1 in ordered representation
+          OrderedBits = OrderedBits + APInt(BitWidth, 1);
+        }
+        
+        // Check for overflow/underflow in ordered representation
+        // If we overflowed past max float or underflowed past min float, skip
+        if (OrderedBits.uge(APInt::getAllOnes(BitWidth)))
+          continue;
+        
+        // Convert back to float bits
+        APInt AdjBits;
+        if (OrderedBits.uge(SignBit)) {
+          // Positive in ordered rep -> was negative in float
+          AdjBits = ~OrderedBits;
+        } else {
+          // Negative in ordered rep -> was positive in float
+          AdjBits = OrderedBits ^ SignBit;
+        }
+        
+        // Convert back to APFloat
+        APFloat TruncAdj(TruncSem, AdjBits);
+        
+        // Double-check for special values
+        if (TruncAdj.isInfinity() || TruncAdj.isNaN())
+          continue;
+        
+        // Convert both C and AdjC to source type and compute midpoint
+        APFloat SrcC = *C;
+        APFloat SrcAdj = TruncAdj;
+        bool losesInfo1, losesInfo2;
+        SrcC.convert(SrcSem, APFloat::rmNearestTiesToEven, &losesInfo1);
+        SrcAdj.convert(SrcSem, APFloat::rmNearestTiesToEven, &losesInfo2);
+        
+        // Midpoint = (C + AdjC) / 2
+        APFloat Midpoint = SrcC;
+        Midpoint.add(SrcAdj, APFloat::rmNearestTiesToEven);
+        APFloat Two(SrcSem, 2);
+        Midpoint.divide(Two, APFloat::rmNearestTiesToEven);
+        
+        Constant *NewC = ConstantFP::get(SrcTy, Midpoint);
+        return new FCmpInst(Pred, X, NewC, "", &I);
+      }
+    }
+  }
   // TODO: Handle non-zero compare constants.
   // TODO: Handle other predicates.
   if (match(Op0, m_OneUse(m_Intrinsic<Intrinsic::copysign>(m_APFloat(C),

