  // fcmp (fptrunc X), C -> fcmp X, threshold(C, pred)
  // Fold comparison of truncated value to a comparison of the original value
  // to a computed threshold. For round-to-nearest truncation, the threshold
  // is the midpoint between C and the adjacent float value.
  if (match(Op0, m_FPTrunc(m_Value(X)))) {
    Type *SrcTy = X->getType()->getScalarType();
    Type *TruncTy = Op0->getType()->getScalarType();
    const APFloat *C;
    const fltSemantics &SrcSem = SrcTy->getFltSemantics();
    const fltSemantics &TruncSem = TruncTy->getFltSemantics();

    // Only handle different IEEE-like floating point types where source is wider
    if (SrcTy->isFloatingPointTy() && TruncTy->isFloatingPointTy() &&
        &SrcSem != &TruncSem && TruncTy->isIEEELikeFPTy() &&
        SrcSem.precision > TruncSem.precision && match(Op1, m_APFloat(C))) {

      // Determine which adjacent float value we need based on predicate
      // For oge/ult: need midpoint(C, prev_float(C))
      // For ole/ogt: need midpoint(C, next_float(C))
      bool NeedPrevFloat = (Pred == FCmpInst::FCMP_OGE ||
                            Pred == FCmpInst::FCMP_UGE ||
                            Pred == FCmpInst::FCMP_ULT);
      bool NeedNextFloat = (Pred == FCmpInst::FCMP_OLE ||
                            Pred == FCmpInst::FCMP_ULE ||
                            Pred == FCmpInst::FCMP_OGT ||
                            Pred == FCmpInst::FCMP_UGT);

      if (NeedPrevFloat || NeedNextFloat) {
        // Get the bit representation of C
        APFloat TruncC = *C;
        APInt TruncBits = TruncC.bitcastToAPInt();
        unsigned BitWidth = TruncBits.getBitWidth();

        // Compute adjacent float by manipulating bits
        // For IEEE floats: incrementing bits moves toward +inf, decrementing toward -inf
        bool IsNegative = TruncC.isNegative();
        APInt AdjBits;

        if (NeedPrevFloat) {
          // Previous float (toward -inf)
          if (IsNegative)
            AdjBits = TruncBits + APInt(BitWidth, 1);
          else
            AdjBits = TruncBits - APInt(BitWidth, 1);
        } else {
          // Next float (toward +inf)
          if (IsNegative)
            AdjBits = TruncBits - APInt(BitWidth, 1);
          else
            AdjBits = TruncBits + APInt(BitWidth, 1);
        }

        // Convert back to APFloat
        APFloat TruncAdj(TruncSem, AdjBits);

        // Check for special values (infinity, NaN)
        if (!TruncAdj.isInfinity() && !TruncAdj.isNaN()) {
          // Convert both C and AdjC to source type and compute midpoint
          APFloat SrcC = *C;
          APFloat SrcAdj = TruncAdj;
          bool losesInfo1, losesInfo2;
          SrcC.convert(SrcSem, APFloat::rmNearestTiesToEven, &losesInfo1);
          SrcAdj.convert(SrcSem, APFloat::rmNearestTiesToEven, &losesInfo2);

          // Midpoint = (C + AdjC) / 2
          APFloat Midpoint = SrcC;
          Midpoint.add(SrcAdj, APFloat::rmNearestTiesToEven);
          Midpoint.divide(APFloat::getTwo(SrcSem), APFloat::rmNearestTiesToEven);

          Constant *NewC = ConstantFP::get(SrcTy, Midpoint);
          return new FCmpInst(Pred, X, NewC, "", &I);
        }
      }
    }
  }
